{
  "exercises": [
    {
      "sourceText": "Ich habe ein Handy.",
      "modelAnswer": "J'ai un téléphone.",
      "alternatives": [
        "Je possède un portable."
      ],
      "keyPoints": [
        "Pronom personnel 'ich' → 'je'",
        "Verbe 'haben' au présent → 'avoir'",
        "Nom 'Handy' → 'téléphone' ou 'portable'",
        "Article défini 'ein' → 'un'"
      ]
    },
    {
      "sourceText": "Das Buch ist groß.",
      "modelAnswer": "Le livre est grand.",
      "alternatives": [
        "Ce livre est grand."
      ],
      "keyPoints": [
        "Déterminant neutre 'das' → 'le'",
        "Nom 'Buch' → 'livre'",
        "Adjectif 'groß' → 'grand'",
        "Verbe 'sein' au présent → 'être'"
      ]
    },
    {
      "sourceText": "Ich sehe den Computer.",
      "modelAnswer": "Je vois l'ordinateur.",
      "alternatives": [
        "Je regarde l’ordinateur."
      ],
      "keyPoints": [
        "Pronom personnel 'ich' → 'je'",
        "Verbe 'sehen' au présent → 'voir'",
        "Nom 'Computer' → 'ordinateur'",
        "Article défini 'den' → 'l'"
      ]
    },
    {
      "sourceText": "Das Gerät ist neu.",
      "modelAnswer": "L'appareil est neuf.",
      "alternatives": [
        "Ce dispositif est nouveau."
      ],
      "keyPoints": [
        "Nom 'Gerät' → 'appareil'",
        "Adjectif 'neu' → 'neuf'",
        "Verbe 'sein' au présent → 'être'",
        "Article défini 'das' → 'l'"
      ]
    },
    {
      "sourceText": "Ich brauche ein Tablet.",
      "modelAnswer": "J'ai besoin d'une tablette.",
      "alternatives": [
        "Je veux une tablette."
      ],
      "keyPoints": [
        "Pronom personnel 'ich' → 'je'",
        "Verbe 'brauchen' au présent → 'avoir besoin de'",
        "Nom 'Tablet' → 'tablette'",
        "Article défini 'ein' → 'une'"
      ]
    }
  ]
}
